import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import response from './response.json';

interface TimeZone {
  city: string;
  time: string;
  dayNight: string;
  analogClock: {
    hour: number;
    minute: number;
  };
}

interface WorldClockData {
  timeZones: TimeZone[];
}

export default function Widget() {
  const worldClockData = response.data as WorldClockData;
  const { timeZones } = worldClockData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          {timeZones.slice(0, 4).map((zone) => (
            <Box key={zone.city} sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <Typography variant="body1" fontWeight={600} sx={{ color: '#000000' }}>
                {zone.city}
              </Typography>
              <Typography variant="body2" sx={{ color: zone.dayNight === 'day' ? '#3B82F6' : '#F97316' }}>
                {zone.time}
              </Typography>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
